// __DEPLOYBOT_BUNDLE__

// ── Router: full state-machine for deploybot ──────────────────────────────────
// Reads the incoming Telegram message, decides what to do next, emits one item
// with fields: { action, chatId, text?, payload? }
// action = 'ask' | 'submit' | 'reply'
//
// The LLM intake call (clarifying questions) is made here via the n8n HTTP helper so the
// graph stays minimal. The runner POST is also done here for the same reason.
// Telegram delivery is handled by the downstream "Telegram Send" node.
// ─────────────────────────────────────────────────────────────────────────────

const cfg  = $('Config').first().json;
const base = cfg.base     || 'https://opencode.ai/zen/go/v1';
const lang = cfg.language || 'Polish';
const apiKey = cfg.apiKey || '';
const intakeModel = cfg.intakeModel || 'kimi-k2.7-code';

const msg    = $input.first().json.message || {};
const chatId = String(msg.chat && msg.chat.id ? msg.chat.id : '');
const text   = (msg.text || '').trim();

const store = $getWorkflowStaticData('global');

// session ─────────────────────────────────────────────────────────────────────
const session = getSession(store, chatId);

// /reset command ──────────────────────────────────────────────────────────────
if (/^\/reset\b/i.test(text)) {
  reset(session);
  return [{ json: { action: 'reply', chatId, text: 'Zresetowałem sesję. Opisz aplikację, którą chcesz zbudować.' } }];
}

// /start or /help ─────────────────────────────────────────────────────────────
if (/^\/start\b|^\/help\b/i.test(text)) {
  return [{ json: {
    action: 'reply', chatId,
    text: 'Cześć! Opisz aplikację webową, którą chcesz zbudować, a ja zajmę się resztą.\n\nKomendy:\n/status — co się teraz dzieje\n/reset — zacznij od nowa'
  } }];
}

// /status command — show what the builder is doing right now
if (/^\/status\b/i.test(text)) {
  let reply = 'Brak aktywnych zadań. Opisz aplikację, aby zacząć.';
  try {
    const st = await helpers.httpRequest({ method: 'GET', url: RUNNER_URL.replace(/\/jobs$/, '/status'), json: true });
    if (st.current) {
      reply = '🔧 Buduję: ' + st.current.job.appName + ' (' + st.current.status + ')';
      if (st.currentLog) reply += '\n\n— ostatnie logi agenta —\n' + st.currentLog;
    } else if (st.recent && st.recent.length) {
      const r = st.recent[0];
      reply = 'Ostatnie zadanie: ' + r.job.appName + ' → ' + r.status + (r.link ? '\n' + r.link : '') + (r.error ? '\n' + r.error : '');
    }
  } catch (e) {
    reply = 'Nie mogę połączyć się z runnerem: ' + (e && e.message ? e.message : String(e));
  }
  return [{ json: { action: 'reply', chatId, text: reply } }];
}

// ── Phase: idle ──────────────────────────────────────────────────────────────
if (session.phase === 'idle') {
  if (!text) {
    return [{ json: { action: 'reply', chatId, text: 'Opisz aplikację, którą chcesz zbudować.' } }];
  }
  // Already have a deployed app? Treat this message as an UPDATE to it (until /reset).
  if (session.currentApp) {
    const upd = buildJobPayload({ chatId, description: text, answers: {} }, session.currentApp, true);
    try {
      await helpers.httpRequest({ method: 'POST', url: RUNNER_URL, body: upd, json: true });
    } catch (e) {
      return [{ json: { action: 'reply', chatId, text: 'Nie udało się zlecić aktualizacji: ' + (e && e.message ? e.message : String(e)) } }];
    }
    return [{ json: { action: 'reply', chatId, text: '🔧 Aktualizuję „' + session.currentApp + '"… /reset = nowa aplikacja.' } }];
  }
  // Call the intake LLM to get clarifying questions
  const systemPrompt = intakeSystemPrompt(lang);
  const llmBody = {
    model: intakeModel,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user',   content: text }
    ],
    max_tokens: 512
  };
  let llmText = '';
  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: base + '/chat/completions',
      headers: { 'Authorization': 'Bearer ' + apiKey },
      body: llmBody,
      json: true,
    });
    llmText = resp?.choices?.[0]?.message?.content || '';
  } catch (e) {
    llmText = '{"questions":[]}';
  }
  const { questions } = parseIntake(llmText);
  // Store draft in session
  const draft = {
    chatId,
    description: text,
    questions,
    answers: {},
    answerIndex: 0
  };
  if (questions.length === 0) {
    // No questions — ask for subdomain immediately
    startClarifying(session, draft);
    session.draft.awaitingSubdomain = true;
    return [{ json: {
      action: 'ask', chatId,
      text: 'Jak ma się nazywać subdomena Twojej aplikacji? (np. `moj-projekt`)'
    } }];
  }
  startClarifying(session, draft);
  return [{ json: { action: 'ask', chatId, text: questions[0] } }];
}

// ── Phase: clarifying ─────────────────────────────────────────────────────────
if (session.phase === 'clarifying') {
  const draft = session.draft;

  // Are we waiting for a subdomain answer?
  if (draft.awaitingSubdomain) {
    const sub = extractSubdomain(text) || text.toLowerCase().replace(/[^a-z0-9-]/g, '');
    if (!isValidSubdomain(sub)) {
      return [{ json: {
        action: 'ask', chatId,
        text: 'Subdomena jest nieprawidłowa. Użyj małych liter, cyfr i myślników (np. `moj-projekt`).'
      } }];
    }
    draft.subdomain = sub;
    // Ready to submit!
    markBuilding(session);
    const payload = buildJobPayload(draft, sub, false);
    // POST to runner
    try {
      await helpers.httpRequest({
        method: 'POST',
        url: RUNNER_URL,
        body: payload,
        json: true,
      });
    } catch (e) {
      reset(session);
      return [{ json: {
        action: 'reply', chatId,
        text: 'Nie udało się zlecić zadania: ' + (e && e.message ? e.message : String(e))
      } }];
    }
    session.phase = 'idle';
    session.draft = null;
    session.currentApp = sub;
    return [{ json: {
      action: 'reply', chatId,
      text: 'Zadanie przyjęte! Buduję aplikację — wyślę link, gdy będzie gotowa.\nKolejne wiadomości zaktualizują tę aplikację. /reset = nowa.'
    } }];
  }

  // Still collecting answers to questions
  const qi = draft.answerIndex || 0;
  const q  = draft.questions[qi];
  draft.answers[q] = text;
  draft.answerIndex = qi + 1;

  if (draft.answerIndex < draft.questions.length) {
    // More questions
    return [{ json: { action: 'ask', chatId, text: draft.questions[draft.answerIndex] } }];
  }
  // All answered — ask for subdomain
  draft.awaitingSubdomain = true;
  return [{ json: {
    action: 'ask', chatId,
    text: 'Jak ma się nazywać subdomena Twojej aplikacji? (np. `moj-projekt`)'
  } }];
}

// ── Phase: building ───────────────────────────────────────────────────────────
if (session.phase === 'building') {
  return [{ json: {
    action: 'reply', chatId,
    text: 'Twoja aplikacja jest już w kolejce do budowania. Poczekaj chwilę lub wpisz /reset, aby zacząć od nowa.'
  } }];
}

// Fallback
return [{ json: { action: 'reply', chatId, text: 'Opisz aplikację, którą chcesz zbudować.' } }];
